import{_ as a,o as t,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"53. Unpaid Pre Adoption Leave","description":"","frontmatter":{"title":"53. Unpaid Pre Adoption Leave","eba":"Medical Specialists 2022-2026","topics":["leave","parental-leave","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/53-unpaid-pre-adoption-leave.md","filePath":"ebas/medical-specialists/leave/53-unpaid-pre-adoption-leave.md"}'),n={name:"ebas/medical-specialists/leave/53-unpaid-pre-adoption-leave.md"};function r(p,e,d,s,l,c){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_53-unpaid-pre-adoption-leave" tabindex="-1">53. Unpaid Pre Adoption Leave <a class="header-anchor" href="#_53-unpaid-pre-adoption-leave" aria-label="Permalink to &quot;53. Unpaid Pre Adoption Leave&quot;">​</a></h1><p><strong>53.1</strong> A Doctor seeking to adopt a child is, on the production of satisfactory evidence if required, entitled to unpaid leave for the purpose of attending any interviews or examinations necessary to the adoption procedure.</p><p><strong>53.2</strong> The Doctor and the Health Service may agree on the length of the unpaid leave.</p><p><strong>53.3</strong> Where agreement cannot be reached, the Doctor is entitled to take up to two days unpaid leave.</p><p><strong>53.4</strong> Where paid leave is available to the Doctor, the Health Service may require the Doctor to take such leave instead.</p><p>Plain language terms: adoption leave.</p>',6)])])}const _=a(n,[["render",r]]);export{h as __pageData,_ as default};
